def gen(rng, size):
    n = rng.randrange(1, max(2, size) + 1)
    coins = [c for c in range(1, n + 1) if rng.random() < 0.5]
    dp = [0] * (n + 1)
    dp[0] = 1
    for c in coins:
        for a in range(c, n + 1):
            dp[a] += dp[a - c]
    nw = dp[1:]
    if rng.random() < 0.3 and n >= 1:
        idx = rng.randrange(0, n)
        nw[idx] = nw[idx] + rng.randrange(1, 4)
    return [nw]

