from itertools import combinations
class Solution:
    def findCoins(self, numWays):
        n = len(numWays)
        def ways(coins):
            dp = [0] * (n + 1)
            dp[0] = 1
            for c in coins:
                for a in range(c, n + 1):
                    dp[a] += dp[a - c]
            return dp[1:]
        for r in range(0, n + 1):
            for combo in combinations(range(1, n + 1), r):
                if ways(combo) == numWays:
                    return sorted(combo)
        return []

