class Solution:
    def findCoins(self, numWays):
        n = len(numWays)
        dp = [0] * (n + 1)
        dp[0] = 1
        coins = []
        for a in range(1, n + 1):
            if dp[a] < numWays[a - 1]:
                coins.append(a)
                for b in range(a, n + 1):
                    dp[b] += dp[b - a]
            if dp[a] != numWays[a - 1]:
                return []
        return coins

