var findCoins = function(numWays) {
    const n = numWays.length;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    const coins = [];
    for (let a = 1; a <= n; a++) {
        if (dp[a] < numWays[a - 1]) {
            coins.push(a);
            for (let b = a; b <= n; b++) dp[b] += dp[b - a];
        }
        if (dp[a] !== numWays[a - 1]) return [];
    }
    return coins;
};
